	ll res = 1;

	while (n) {

		if (n & 1)res = res * a % m;

		a = a * a%m; n >>= 1;

	}

	return res;

}



void solve(){

  int n, k; cin >> n >> k;

  ll lw = 1, up = 1, ans = 0;



